if (!line || strlen(line) <= 4) return NULL;
    const char *p = line;
    while (*p && *p != '\n') p++;
    size_t len = p - line;
    if (len == 0) return NULL;
    unsigned char *fname = malloc(len + 1);
    if (!fname) return NULL;
    memcpy(fname, line, len);
    fname[len] = '\0';
    if (patch_level == (unsigned short)-1) {
        char *last = strrchr((char *)fname, '/');
        if (last) {
            memmove(fname, last + 1, strlen(last));
        }
    } else {
        for (int i = 0; i < patch_level; ++i) {
            char *next = strchr((char *)fname, '/');
            if (!next) break;
            memmove(fname, next + 1, strlen(next));
        }
    }
    return fname;
}

