#include <string.h>

static unsigned char *extract_filename(char *line, unsigned short patch_level) {
    if (patch_level == -1) {
        // Remove all directory names
        char *filename = strrchr(line, '/');
        if (filename == NULL) {
            // No directory names, return the original line
            filename = line;
        } else {
            // Skip the '/' character
            filename++;
        }

        // Check if the filename is greater than 4 chars
        if (strlen(filename) > 4) {
            // Allocate memory for the filename and copy it
            unsigned char *result = malloc(strlen(filename) + 1);
            if (result == NULL) {
                // Error allocating memory
                return NULL;
            }
            strcpy((char *)result, filename);
            return result;
        } else {
            // Filename is not greater than 4 chars
            return NULL;
        }
    } else {
        // patch_level is not -1, return NULL
        return NULL;
    }
}

