    if (symbolCount >= MAX_SYMBOLS) {
        printf("Error: Symbol table is full.\n");
        return;
    }

    if (strlen(name) >= MAX_SYMBOL_LENGTH) {
        printf("Error: Symbol name is too long.\n");
        return;
    }

    Symbol* symbol = &symbolTable[symbolCount];
    strcpy(symbol->name, name);
    symbol->type = type;
    symbol->value = value;

    symbolCount++;
}

