uint32_t USB_CDC_Read(uint8_t* c) {
if (c == NULL) {
        return (uint32_t)-1;
    }
    extern uint8_t usb_cdc_rx_buffer[256];
    extern volatile uint16_t usb_cdc_rx_head;
    extern volatile uint16_t usb_cdc_rx_tail;
    if (usb_cdc_rx_head == usb_cdc_rx_tail) {
        return (uint32_t)-1;
    }
    *c = usb_cdc_rx_buffer[usb_cdc_rx_tail];
    usb_cdc_rx_tail = (usb_cdc_rx_tail + 1) & 0xFF;
    return (uint32_t)(usb_cdc_rx_head - usb_cdc_rx_tail);
}

