// Assuming you have a buffer and a function to get data from the buffer
uint8_t buffer[1024];
uint32_t buffer_size = 0;

// Function to get data from the buffer
int get_data_from_buffer(uint8_t* c) {
    if (buffer_size == 0) {
        return -1;
    }
    *c = buffer[0];
    // Shift the buffer
    for (uint32_t i = 0; i < buffer_size - 1; i++) {
        buffer[i] = buffer[i + 1];
    }
    buffer_size--;
    return buffer_size;
}

uint32_t USB_CDC_Read(uint8_t* c) {
    return get_data_from_buffer(c);
}

