  if(*s++ != '#') {
    printf("Color code must begin with '#' (see \"%s\")\n", s);
    return -1u;
  }
  uint32_t ret = 0u;
  int shift = 20;
  for(int i = 0;i < 6;i++) {
    char ch = *s++;
    if(ch == '\0') {
      printf("Unexpected end of color code\n");
      return -1u;
    }
    uint32_t hex;
    if((ch >= '0' && ch <= '9')) {
      hex = (uint32_t)(ch - '0');
    } else if(ch >= 'a' && ch <= 'f') {
      hex = (uint32_t)(ch - 'a' + 10);
    } else if(ch >= 'A' && ch <= 'F') {
      hex = (uint32_t)(ch - 'A' + 10);
    } else {
      const char *rgb;
      if(i <= 1) rgb = "Red";
      else if(i <= 3) rgb = "Green";
      else rgb = "Blue";
      printf("Invalid color code: \"%s\"; Component \"%s\" contains invalid digit\n", s, rgb);
      return -1u;
    }
    assert((hex & ~0xffu) == 0);
    ret |= (hex << shift);
    shift -= 4;
  }
  if(*s != '\0') {
    printf("Unexpected character after color code\n");
    return -1u;
  }
  return ret;
}

