    char *token = strtok(line, " \t");
    int i = 0;

    while (token != NULL) {
        if (i == 0) {
            strcpy(tzentry->name, token);
        } else if (i == 1) {
            strcpy(tzentry->zone, token);
        } else if (i == 2) {
            strcpy(tzentry->offset, token);
        } else if (i == 3) {
            strcpy(tzentry->dst, token);
        } else {
            return false; // too many tokens
        }

        token = strtok(NULL, " \t");
        i++;
    }

    if (i < 2 || i > 4) {
        return false; // not enough or too many tokens
    }

    return true;
}

