			break;
		}
	}
	if (eof) {
		result = xmalloc(sizeof(int));
		*result = EOF;
	} else {
		int j = 0;
		if (!nr) {
			for (i = 0; i < stuff->nr; i++)
				nr += chosen[i];
		}
		result = xcalloc(st_add(nr, 1), sizeof(int));
		for (i = 0; i < stuff->nr && j < nr; i++) {
			if (chosen[i])
				result[j++] = i;
		}
		result[j] = EOF;
	}
	free(chosen);
	strbuf_release(&choice);
