    // If user pressed CTRL-D, no selection returned
    if (count == 0) {
        free(array);
        return NULL;
    }

    // Return an array of integers
    int* result = malloc(sizeof(int) * count);
    for (int i = 0; i < count; i++) {
        result[i] = array[i];
    }
    free(array);

    return result;
}

