        return TCL_ERROR;
    }
    struct tm *utc_tm = gmtime(&local_time);
    if (!utc_tm) {
        Tcl_SetResult(interp, "Failed to convert to UTC", TCL_STATIC);
        return TCL_ERROR;
    }
    fields->sec = utc_tm->tm_sec;
    return TCL_OK;
}

