char * resolve_rel_url( char * base_url, char * rel_url) {
if (!rel_url) return NULL;
    // Check if rel_url is absolute (starts with scheme:// or //)
    const char *p = rel_url;
    while (*p && (*p == ' ' || *p == '\t')) p++;
    if (strchr(p, ':') != NULL) {
        // contains a colon, assume absolute
        return strdup(rel_url);
    }
    if (strncmp(p, "//", 2) == 0) {
        // protocol-relative URL, prepend scheme from base_url if available
        if (base_url) {
            const char *scheme_end = strstr(base_url, "://");
            if (scheme_end) {
                size_t scheme_len = scheme_end - base_url + 3; // include ://
                size_t rel_len = strlen(p);
                char *result = malloc(scheme_len + rel_len + 1);
                if (!result) return NULL;
                memcpy(result, base_url, scheme_len);
                memcpy(result + scheme_len, p, rel_len + 1);
                return result;
            }
        }
        return strdup(rel_url);
    }
    // If base_url is NULL, cannot resolve relative
    if (!base_url) return NULL;
    // Ensure base_url ends with '/'
    size_t base_len = strlen(base_url);
    int need_slash = 0;
    if (base_len == 0 || base_url[base_len-1] != '/') need_slash = 1;
    size_t rel_len = strlen(rel_url);
    size_t total_len = base_len + need_slash + rel_len + 1;
    char *result = malloc(total_len);
    if (!result) return NULL;
    strcpy(result, base_url);
    if (need_slash) result[base_len] = '/';
    strcpy(result + base_len + need_slash, rel_url);
    return result;
}

