// Check if the SPTE has the present bit set
    if (!(spte & (1ULL << 0))) {
        return NULL;
    }
    // Extract the physical address bits from the SPTE
    // Assuming the physical address occupies bits [12:51] in the SPTE
    u64 pa = (spte >> 12) & 0xFFFFFFFFFFULL;
    // Convert physical address to host virtual address
    // Assuming a simple identity mapping for the example
    u64 *child_pt = (u64 *)(uintptr_t)(pa);
    return child_pt;
}

