void _lv_txt_ins(char * txt_buf, uint32_t pos, const char * ins_txt) {
if(txt_buf == NULL || ins_txt == NULL) return;
    /* Find the byte offset corresponding to the character position */
    uint32_t byte_pos = 0;
    uint32_t char_idx = 0;
    while(txt_buf[byte_pos] != '\0' && char_idx < pos) {
        /* Skip over UTF-8 encoded characters */
        unsigned char c = (unsigned char)txt_buf[byte_pos];
        if(c < 0x80) {
            byte_pos += 1;
        } else if((c >> 5) == 0x6) {
            byte_pos += 2;
        } else if((c >> 4) == 0xE) {
            byte_pos += 3;
        } else if((c >> 3) == 0x1E) {
            byte_pos += 4;
        } else {
            /* Invalid UTF-8, treat as single byte */
            byte_pos += 1;
        }
        char_idx++;
    }
    /* Insert the new text at the calculated byte position */
    size_t ins_len = strlen(ins_txt);
    size_t rest_len = strlen(txt_buf + byte_pos) + 1; /* include null terminator */
    memmove(txt_buf + byte_pos + ins_len, txt_buf + byte_pos, rest_len);
    memcpy(txt_buf + byte_pos, ins_txt, ins_len);
}

