            return -1;
        }
        memcpy(node->data, (const char *)buf + written, remaining);
        node->len = remaining;
        node->next = NULL;
        /* Enqueue node */
        if (!vuart->list_head) {
            vuart->list_head = vuart->list_tail = node;
        } else {
            vuart->list_tail->next = node;
            vuart->list_tail = node;
        }
        /* Enable transmit interrupt to process list */
        ps3_vuart_enable_tx_irq(dev);
    }
    return bytes;
}

