        return;
    }
    out.writeInt(array.length);
    for (String str : array) {
        if (str == null) {
            out.writeInt(-1);
        } else {
            byte[] bytes = str.getBytes(StandardCharsets.UTF_8);
            out.writeInt(bytes.length);
            out.write(bytes);
        }
    }
}

