public void setStackTraceElement(Throwable throwable, Class<?> clazz, String methodName) {
    StackTraceElement[] stackTrace = throwable.getStackTrace();
    StackTraceElement newStackTraceElement = new StackTraceElement(clazz.getName(), methodName, null, -1);

    for (int i = 0; i < stackTrace.length; i++) {
        if (stackTrace[i].getClassName().equals(clazz.getName()) && stackTrace[i].getMethodName().equals(methodName)) {
            stackTrace[i] = newStackTraceElement;
            throwable.setStackTrace(stackTrace);
            return;
        }
    }

    StackTraceElement[] newStackTrace = new StackTraceElement[stackTrace.length + 1];
    System.arraycopy(stackTrace, 0, newStackTrace, 0, stackTrace.length);
    newStackTrace[newStackTrace.length - 1] = newStackTraceElement;
    throwable.setStackTrace(newStackTrace);
}

