private VirtualMachine listenTarget(int port, List<String> remoteVMOptions) {
	// Create a ListeningConnector
    ListeningConnector listeningConnector = findListeningConnector();
    // Set the port number for the ListeningConnector
    Map<String, Connector.Argument> arguments = listeningConnector.defaultArguments();
    Connector.Argument portArgument = arguments.get("port");
    portArgument.setValue(String.valueOf(port));

    // Start the ListeningConnector
    VirtualMachineManager vmm = Bootstrap.virtualMachineManager();
    VirtualMachine vm = listeningConnector.accept(arguments);
