private ListeningConnector findListeningConnector() {
    // Find the ListeningConnector
    List<Connector> connectors = Bootstrap.virtualMachineManager().allConnectors();
    for (Connector connector : connectors) {
        if (connector instanceof ListeningConnector) {
            return (ListeningConnector) connector;
        }
    }
    throw new RuntimeException("No ListeningConnector found");
}

private void startRemoteAgent(int port, List<String> remoteVMOptions) {
    // Start the remote agent
    ProcessBuilder processBuilder = new ProcessBuilder("java", "-agentlib:jdwp=transport=dt_socket,server=y,suspend=n,address=" + port);
    processBuilder.command().addAll(remoteVMOptions);
    try {
        Process process = processBuilder.start();
        // Optionally, you can wait for the process to start
        process.waitFor(5, TimeUnit.SECONDS);
    } catch (IOException | InterruptedException e) {
        e.printStackTrace();
    }
}

public void connectToRemoteVM(int port, List<String> remoteVMOptions) {
    // Start the remote agent
    startRemoteAgent(port, remoteVMOptions);
    // Connect to the remote VM
    VirtualMachine vm = listenTarget(port, remoteVMOptions);
    System.out.println("Connected to remote VM: " + vm);
