public static boolean isStartOfChunk(String prevTag, String prevType, String curTag, String curType) {
    // Check if the previous token is null or if the current token is the first token of a chunk
    if (prevTag == null || prevType == null) {
        return true;
    }

    // Check if the current token is the first token of a chunk
    if (prevTag.equals(".") || prevTag.equals(":") || prevTag.equals(";") || prevTag.equals("!")) {
        return true;
    }

    // Check if the current token is the first token of a chunk
    if (prevType.equals(".") || prevType.equals(":") || prevType.equals(";") || prevType.equals("!")) {
        return true;
    }

    // If none of the above conditions are met, then the current token is not the first token of a chunk
    return false;
}

