        int index = 0;
        E value = null;

        for(int i = 1; i < array.length; i++) {
            index = i;
            value = array[index];
            while(index > 0 && value.compareTo(array[index - 1]) < 0) {
                array[index] = array[index - 1];

                index--;
            }

            array[index] = value;
        }
    }

