import java.util.logging.Level;

public static void printAsciiArtLog(VoltLogger vLogger, String msg, Level level) {
    int maxLineLength = 50; // Adjust this value as needed
    String[] words = msg.split(" ");
    StringBuilder sb = new StringBuilder();
    int lineLength = 0;

    for (String word : words) {
        if (lineLength + word.length() > maxLineLength) {
            sb.append("\n* ");
            lineLength = 0;
        }
        sb.append(word);
        sb.append(' ');
        lineLength += word.length() + 1;
    }

    String wrappedMsg = sb.toString();
    String stars = "*".repeat(Math.max(wrappedMsg.length(), maxLineLength));

    vLogger.log(level, stars + "\n* " + wrappedMsg + " *\n" + stars);
}

