public class ByteBufferExample {

    private ByteBuffer buffer;

    public ByteBufferExample(int capacity) {
        buffer = ByteBuffer.allocate(capacity);
    }

    public synchronized void putString(String item) {
        byte[] bytes = item.getBytes(StandardCharsets.UTF_8);
        if (buffer.remaining() < bytes.length) {
            throw new IllegalArgumentException("Not enough space in buffer");
        }
        buffer.put(bytes);
    }

    public ByteBuffer getBuffer() {
        return buffer;
    }

    public static void main(String[] args) {
        ByteBufferExample example = new ByteBufferExample(1024);
        example.putString("Hello, World!");
        ByteBuffer buffer = example.getBuffer();
        buffer.flip();
        byte[] bytes = new byte[buffer.limit()];
        buffer.get(bytes);
        String result = new String(bytes, StandardCharsets.UTF_8);
        System.out.println(result);  // Outputs: Hello, World!
    }
}

