public Map<String, String> buildRoot(HttpServletRequest request) {
    Map<String, String> map = new HashMap<>();

    // Get the query string from the request
    String queryString = request.getQueryString();

    // If the query string is not null
    if (queryString != null) {
        // Split the query string into key-value pairs
        String[] pairs = queryString.split("&");

        for (String pair : pairs) {
            // Split each pair into key and value
            String[] keyValue = pair.split("=");

            // If the key-value pair has exactly two elements
            if (keyValue.length == 2) {
                // Add the key-value pair to the map
                map.put(keyValue[0], keyValue[1]);
            }
        }
    }

    // Set default values
    map.putIfAbsent("key1", "defaultValue1");
    map.putIfAbsent("key2", "defaultValue2");

    return map;
}

