public List<String> loadAll(Table hTable, int rows, String columnFamily, List<String> columns)
    throws IOException {
  List<String> resultList = new ArrayList<>();

  Scan scan = new Scan();
  scan.setCaching(rows);
  for (String column : columns) {
    scan.addColumn(Bytes.toBytes(columnFamily), Bytes.toBytes(column));
  }

  ResultScanner resultScanner = hTable.getScanner(scan);

  for (Result result : resultScanner) {
    byte[] value = result.getValue(Bytes.toBytes(columnFamily), Bytes.toBytes(columns.get(0)));
    String row = Bytes.toString(result.getRow());
    resultList.add(String.format("%s,%s", row, value));
  }

  return resultList;
}

