public List<HBaseDataWrapper> loadAll(final Table hTable, final List<Object> rows, final String columnFamily, final String[] columns) throws IOException {
    List<HBaseDataWrapper> result = new ArrayList<>();

    for (Object row : rows) {
        Get get = new Get(Bytes.toBytes((String) row));
        for (String column : columns) {
            get.addFamily(Bytes.toBytes(columnFamily));
            get.addColumn(Bytes.toBytes(columnFamily), Bytes.toBytes(column));
        }

        Result res = hTable.get(get);
        if (!res.isEmpty()) {
            HBaseDataWrapper wrapper = new HBaseDataWrapper();
            for (String column : columns) {
                byte[] value = res.getValue(Bytes.toBytes(columnFamily), Bytes.toBytes(column));
                wrapper.addData(column, Bytes.toString(value));
            }
            result.add(wrapper);
        }
    }

    return result;
}

