private static String findFirstGeometryColumn(Connection connection, String tableName) throws SQLException {
    // Prepare the SQL query to find the first geometry column
    String sql = "SELECT column_name FROM information_schema.columns WHERE table_name = ? AND data_type LIKE '%geometry%' LIMIT 1";

    // Execute the query
    PreparedStatement preparedStatement = connection.prepareStatement(sql);
    preparedStatement.setString(1, tableName);
    ResultSet resultSet = preparedStatement.executeQuery();

    // Check if a geometry column is found
    if (resultSet.next()) {
        return resultSet.getString("column_name");
    } else {
        throw new SQLException("No geometry column found in table " + tableName);
    }
}

