def _ensure_systemd(version):
    import subprocess
    import re
    try:
        output = subprocess.check_output(['systemctl', '--version'])
    except subprocess.CalledProcessError:
        raise Exception('Failed to get systemd version')
    match = re.search('systemd (\\d+\\.\\d+\\.\\d+)', output.decode('utf-8'))
    if not match:
        raise Exception('Failed to parse systemd version')
    current_version = match.group(1)
    if not _compare_versions(current_version, version):
        raise Exception(f'Systemd version {current_version} is not greater than {version}')

def _compare_versions(current, required):
    """Compares two version strings."""
    current_parts = list(map(int, current.split('.')))
    required_parts = list(map(int, required.split('.')))
    for (c, r) in zip(current_parts, required_parts):
        if c > r:
            return True
        elif c < r:
            return False
    return len(current_parts) > len(required_parts)

