def select_serializer(action_method, extensions, request):
    available_types = set()
    serializers_map = {}

    # get serializers declared on the action method and its extensions
    for extension in extensions:
        serializer = getattr(extension, 'serializer_class', None)
        if serializer:
            available_types.add(serializer.Meta.media_type)
            serializers_map[serializer.Meta.media_type] = serializer

    serializer = getattr(action_method, 'serializer_class', None)
    if serializer:
        available_types.add(serializer.Meta.media_type)
        serializers_map[serializer.Meta.media_type] = serializer

    # select the best match based on the HTTP Accept header
    accepted_types = request.META.get('HTTP_ACCEPT', '').split(',')
    best_match = None
    for accepted_type in accepted_types:
        accepted_type = accepted_type.strip()
        if accepted_type == '*/*':
            best_match = sorted(available_types)[0]
            break
        if accepted_type in available_types:
            best_match = accepted_type
            break

    if not best_match:
        raise NotAcceptable()

    return best_match, serializers_map[best_match]()

