import argparse

def get_children_by_parent(children, gff_file):
    with open(gff_file, 'r') as f:
        lines = f.readlines()
    parents = {}
    for line in lines:
        if not line.startswith('#'):
            parts = line.strip().split('\t')
            if parts[2] == 'gene':
                info = parts[8].split(';')
                gene_id = ''
                gene_parent = ''
                for i in info:
                    if 'ID=' in i:
                        gene_id = i.replace('ID=', '')
                    elif 'Parent=' in i:
                        gene_parent = i.replace('Parent=', '')
                parents[gene_id] = gene_parent

    parent_children = {}
    for child in children:
        if child in parents:
            parent_id = parents[child]
            if parent_id not in parent_children:
                parent_children[parent_id] = []
            parent_children[parent_id].append(child)

    return parent_children


if __name__ == '__main__':
    parser = argparse.ArgumentParser(description='%prog children gff_file')
    parser.add_argument('children', nargs='+', help='List of children')
    parser.add_argument('gff_file', help='Path to GFF file')
    args = parser.parse_args()

    parent_children = get_children_by_parent(args.children, args.gff_file)
    for parent, children in parent_children.items():
        print('Parent:', parent)
        print('Children:', children)

