def resolve_jbor(jbor, job_outputs) -> Any:
    val = None
    for k, v in jbor.items():
        if k == "#":
            continue
        if isinstance(v, dict):
            val = resolve_jbor(v, job_outputs)
        elif isinstance(v, str) and v.startswith("$"):
            if v in job_outputs:
                val = job_outputs[v]
        else:
            if k == v:
                if not val:
                    val = job_outputs[v]
                else:
                    val = {**val, **job_outputs[v]}
    if val is None:
        raise Exception("Job-based object reference cannot be resolved")
    return val

