import requests

def get_all_pages(url_suffix: str, data: object) -> requests.Response:
    result = requests.get(url_suffix, data)
    if 'x-total-pages' not in result.headers or int(result.headers['x-total-pages']) == 1:
        return result
    else:
        total_pages = int(result.headers['x-total-pages'])
        for page_number in range(2, total_pages + 1):
            response = requests.get(url_suffix, params={'page': page_number}, data=data)
            response.raise_for_status()
            result.json()['results'] += response.json()['results']
    return result

