import moderngl

class Renderer:
    def __init__(self, context: moderngl.Context):
        self.context = context

    def render(self, program: moderngl.Program, mode=moderngl.TRIANGLES, vertices=None, first=0, instances=1):
        program['m_proj'].write(self.context.projection_matrix)
        program['m_model'].write(self.context.model_matrix)
        program['m_cam'].write(self.context.camera_matrix)

        if vertices is None:
            vertices = len(self.context.vertices)

        self.context.vertex_array.render(mode, vertices, first, instances)
